"""
T2 Order System -- Product Routes (Gen 1, Sample 2)

Design decisions (intentionally different from a naive implementation):
1. Uses a standalone serialize() helper function to decouple model-to-dict
   conversion from route handlers, making serialization reusable and testable.
2. Explicit field validation via a dedicated _validate_product_fields() function
   that returns structured error info instead of ad-hoc checks inside handlers.
3. Every route handler follows the same three-phase pattern:
     validate -> execute -> serialize, keeping logic flat and predictable.
"""

from flask import Blueprint, request, jsonify

from app import db
from models import Product

product_bp = Blueprint('product_bp', __name__)


# ---------------------------------------------------------------------------
# Serialization helper
# ---------------------------------------------------------------------------

def serialize(product):
    """Convert a Product ORM instance into a plain dict."""
    return {
        'id': product.id,
        'name': product.name,
        'price': product.price,
        'stock': product.stock,
    }


def serialize_list(products):
    """Convert an iterable of Product instances into a list of dicts."""
    return [serialize(p) for p in products]


# ---------------------------------------------------------------------------
# Field validation
# ---------------------------------------------------------------------------

_REQUIRED_FIELDS = {'name', 'price', 'stock'}
_TYPE_COERCION = {
    'name': str,
    'price': (int, float),
    'stock': int,
}


def _validate_product_fields(payload):
    """Validate product creation payload.

    Returns (cleaned_data_dict, error_message_tuple_or_None).
    The error_message_tuple is (field_name, description) suitable for
    building a user-facing error response.
    """
    # Check for missing keys
    missing = _REQUIRED_FIELDS - set(payload.keys())
    if missing:
        return None, (', '.join(sorted(missing)), 'missing required field(s)')

    # Check types and coerce where possible
    cleaned = {}
    for field, expected_type in _TYPE_COERCION.items():
        value = payload[field]
        if not isinstance(value, expected_type):
            return None, (field, f'expected {expected_type.__name__}, got {type(value).__name__}')
        cleaned[field] = value

    # Price must be non-negative
    if cleaned['price'] < 0:
        return None, ('price', 'must be non-negative')

    # Stock must be non-negative
    if cleaned['stock'] < 0:
        return None, ('stock', 'must be non-negative')

    return cleaned, None


# ---------------------------------------------------------------------------
# Route handlers
# ---------------------------------------------------------------------------

@product_bp.route('/products', methods=['GET'])
def list_products():
    """GET /products -- return all products."""
    products = Product.query.all()
    return jsonify({'status': 'ok', 'data': serialize_list(products)}), 200


@product_bp.route('/products', methods=['POST'])
def create_product():
    """POST /products -- create a new product.

    Required JSON body: {name: str, price: float, stock: int}
    """
    payload = request.get_json(silent=True)
    if payload is None:
        return jsonify({'status': 'error', 'message': 'request body must be JSON'}), 400

    cleaned, err = _validate_product_fields(payload)
    if err is not None:
        field, description = err
        return jsonify({'status': 'error', 'message': f'Invalid field "{field}": {description}'}), 400

    product = Product(name=cleaned['name'], price=float(cleaned['price']), stock=int(cleaned['stock']))
    db.session.add(product)
    db.session.commit()

    return jsonify({'status': 'ok', 'data': serialize(product)}), 201


@product_bp.route('/products/<int:product_id>', methods=['GET'])
def get_product(product_id):
    """GET /products/<id> -- return a single product."""
    product = Product.query.get(product_id)
    if product is None:
        return jsonify({'status': 'error', 'message': f'Product {product_id} not found'}), 404

    return jsonify({'status': 'ok', 'data': serialize(product)}), 200

"""
T2 Order System -- Product Routes (Sample 1 / Gen 1)

Evolutionary variant: function-style route handlers with explicit input
validation via request.get_json(silent=True) and helper closures for
consistent response shaping.

Design decisions:
- Each route delegates to a standalone handler function (no class).
- Validation logic is extracted into a separate pure function.
- Response helpers are closures returned from a factory, keeping the
  module namespace clean while avoiding repeated dict literals.
- Uses request.get_json(silent=True) so malformed JSON returns 400
  instead of raising an internal 500.
"""

from flask import Blueprint, request, jsonify
from app import db
from models import Product

product_bp = Blueprint('product_bp', __name__)


# ---------------------------------------------------------------------------
# Response helper factory (closure-based)
# ---------------------------------------------------------------------------

def _make_responders():
    """Return ok() and err() helpers that share the same envelope style."""

    def ok(data=None, status_code=200):
        body = {"status": "ok"}
        if data is not None:
            body["data"] = data
        return jsonify(body), status_code

    def err(message, status_code=400):
        return jsonify({"status": "error", "message": message}), status_code

    return ok, err


ok, err = _make_responders()


# ---------------------------------------------------------------------------
# Serialization helper
# ---------------------------------------------------------------------------

def _serialize_product(p):
    """Convert a Product ORM object to a plain dict."""
    return {
        "id": p.id,
        "name": p.name,
        "price": p.price,
        "stock": p.stock,
    }


# ---------------------------------------------------------------------------
# Input validation (pure function)
# ---------------------------------------------------------------------------

def _validate_create_payload(payload):
    """
    Validate the JSON payload for product creation.

    Returns (cleaned_fields, error_message).
    If validation passes, error_message is None.
    """
    if not isinstance(payload, dict):
        return None, "Request body must be a JSON object"

    required = {"name", "price", "stock"}
    missing = required - set(payload.keys())
    if missing:
        return None, f"Missing required fields: {', '.join(sorted(missing))}"

    name = payload["name"]
    if not isinstance(name, str) or len(name.strip()) == 0:
        return None, "Field 'name' must be a non-empty string"

    try:
        price = float(payload["price"])
        if price < 0:
            return None, "Field 'price' must be >= 0"
    except (TypeError, ValueError):
        return None, "Field 'price' must be a number"

    try:
        stock = int(payload["stock"])
        if stock < 0:
            return None, "Field 'stock' must be >= 0"
    except (TypeError, ValueError):
        return None, "Field 'stock' must be an integer"

    return {"name": name.strip(), "price": price, "stock": stock}, None


# ---------------------------------------------------------------------------
# Route handlers (functional style)
# ---------------------------------------------------------------------------

@product_bp.route("/products", methods=["GET"])
def list_products():
    """GET /products -- return all products."""
    products = Product.query.all()
    return ok([_serialize_product(p) for p in products])


@product_bp.route("/products", methods=["POST"])
def create_product():
    """POST /products -- create a new product."""
    payload = request.get_json(silent=True)
    if payload is None:
        return err("Invalid or missing JSON body")

    fields, error = _validate_create_payload(payload)
    if error:
        return err(error)

    product = Product(name=fields["name"], price=fields["price"], stock=fields["stock"])
    db.session.add(product)
    db.session.commit()

    return ok(_serialize_product(product), status_code=201)


@product_bp.route("/products/<int:product_id>", methods=["GET"])
def get_product(product_id):
    """GET /products/<id> -- return a single product."""
    product = Product.query.get(product_id)
    if product is None:
        return err("Product not found", status_code=404)

    return ok(_serialize_product(product))

